section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/motion-and-microinteraction-spec.json",
  "title": "Motion and Microinteraction Spec",
  "type": "object",
  "required": [
    "artefact_id",
    "component_id",
    "duration_ms",
    "easing",
    "trigger",
    "choreography_ref",
    "reduced_motion_fallback",
    "perceived_perf_budget_ms",
    "platform_targets",
    "evidence",
    "status",
    "owner",
    "last_touched",
    "template_version"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "slug + ISO date or UUID",
      "minLength": 1
    },
    "component_id": {
      "type": "string",
      "description": "component_id",
      "minLength": 1
    },
    "duration_ms": {
      "type": "number",
      "description": "duration_ms (numeric)"
    },
    "easing": {
      "type": "string",
      "description": "easing",
      "minLength": 1
    },
    "trigger": {
      "type": "string",
      "description": "trigger",
      "minLength": 1
    },
    "choreography_ref": {
      "type": "string",
      "description": "choreography_ref",
      "minLength": 1
    },
    "reduced_motion_fallback": {
      "type": "string",
      "description": "reduced_motion_fallback",
      "minLength": 1
    },
    "perceived_perf_budget_ms": {
      "type": "number",
      "description": "perceived_perf_budget_ms (numeric)"
    },
    "platform_targets": {
      "type": "array",
      "description": "platform_targets (array)",
      "minItems": 1
    },
    "evidence": {
      "type": "array",
      "description": "{source, citation} pairs anchoring non-trivial fields",
      "minItems": 1
    },
    "status": {
      "type": "string",
      "description": "draft|ready_for_review|approved|archived",
      "minLength": 1
    },
    "owner": {
      "type": "string",
      "description": "single named owner; generic group terms forbidden",
      "minLength": 1
    },
    "last_touched": {
      "type": "string",
      "description": "ISO-8601 timestamp",
      "format": "date-time"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    }
  },
  "additionalProperties": false
}
